// Extract user data from webhook payload
const payload = $input.first().json.body || $input.first().json;

return [{
  json: {
    userId: payload.data?.userId || 'unknown',
    email: payload.data?.email || '',
    displayName: payload.data?.displayName || '',
    role: payload.data?.role || 'creator',
    xrplAddress: payload.data?.xrplAddress || '',
    event: payload.event || 'user.registered',
    timestamp: payload.timestamp || new Date().toISOString(),
    hasWallet: !!payload.data?.xrplAddress
  }
}];

// Send welcome email placeholder
// TODO: Replace with SendGrid / Resend node when credentials are configured
const user = $input.first().json;

console.log(`[StudioLedger] Welcome email queued for: ${user.email}`);
console.log(`[StudioLedger] User: ${user.displayName} (${user.role})`);
console.log(`[StudioLedger] XRPL Address: ${user.xrplAddress}`);

return [{
  json: {
    ...user,
    welcomeEmailSent: true,
    onboardingStep: 'welcome_email',
    message: `Welcome email queued for ${user.email}`
  }
}];

// No email available — log and continue
const user = $input.first().json;

console.log(`[StudioLedger] No email for user ${user.userId} — skipping welcome email`);

return [{
  json: {
    ...user,
    welcomeEmailSent: false,
    onboardingStep: 'no_email_skip',
    message: `No email available for user ${user.userId}`
  }
}];

// Onboarding complete — compile summary
const user = $input.first().json;

const summary = {
  userId: user.userId,
  email: user.email,
  displayName: user.displayName,
  role: user.role,
  xrplAddress: user.xrplAddress,
  welcomeEmailSent: user.welcomeEmailSent || false,
  onboardedAt: new Date().toISOString(),
  status: 'onboarding_complete'
};

console.log('[StudioLedger] Onboarding complete:', JSON.stringify(summary));

return [{ json: summary }];
